select u.id, u.name, u.sex, u.tel, u.email, d.dept_name as dept,
       u.hiredate, u.root, u.status, GROUP_CONCAT(r.role_name separator '，') as roles
from tb_user u join tb_role r on JSON_CONTAINS(u.role, CAST(r.id as CHAR))
               left join tb_dept d on u.dept_id = d.id



        and u.name like concat('%', #{name}, '%')


        and u.sex = #{sex}


        and r.role_name = #{role}


        and d.id = #{deptId}


        and u.status = #{status}


group by u.id
order by u.id ASC
limit #{start}, #{length}

